def generate_totp_secret():
    """Generate a random base32-encoded secret for TOTP."""
    return base64.b32encode(secrets.token_bytes(20)).decode('utf-8')


def generate_totp(secret, time_step=30, digits=6):
    """Generate a TOTP code based on the shared secret."""
    key = base64.b32decode(secret, casefold=True)
    counter = int(time.time()) // time_step
    counter_bytes = struct.pack('>Q', counter)
    hmac_hash = hmac.new(key, counter_bytes, hashlib.sha1).digest()
    offset = hmac_hash[-1] & 0x0F
    truncated = struct.unpack('>I', hmac_hash[offset:offset + 4])[0] & 0x7FFFFFFF
    code = truncated % (10 ** digits)
    return str(code).zfill(digits)


def verify_totp(secret, code, time_step=30, digits=6, window=1):
    """Verify a TOTP code with a time window tolerance."""
    if not re.match(r'^\d{6}$', code):
        return False
    key = base64.b32decode(secret, casefold=True)
    current_counter = int(time.time()) // time_step
    for offset in range(-window, window + 1):
        counter = current_counter + offset
        counter_bytes = struct.pack('>Q', counter)
        hmac_hash = hmac.new(key, counter_bytes, hashlib.sha1).digest()
        o = hmac_hash[-1] & 0x0F
        truncated = struct.unpack('>I', hmac_hash[o:o + 4])[0] & 0x7FFFFFFF
        expected = str(truncated % (10 ** digits)).zfill(digits)
        if hmac.compare_digest(expected, code):
            return True
    return False


