def is_account_locked(username):
    """Check if an account is locked due to too many failed attempts."""
    if username in login_attempts:
        attempt_info = login_attempts[username]
        if attempt_info.get('locked_until') and datetime.utcnow() < attempt_info['locked_until']:
            return True
        if attempt_info.get('locked_until') and datetime.utcnow() >= attempt_info['locked_until']:
            login_attempts[username] = {'count': 0, 'locked_until': None}
    return False


def record_failed_attempt(username):
    """Record a failed login attempt and lock account if threshold exceeded."""
    if username not in login_attempts:
        login_attempts[username] = {'count': 0, 'locked_until': None}
    login_attempts[username]['count'] += 1
    if login_attempts[username]['count'] >= app.config['MAX_LOGIN_ATTEMPTS']:
        login_attempts[username]['locked_until'] = (
            datetime.utcnow() + timedelta(seconds=app.config['LOCKOUT_DURATION'])
        )


def clear_failed_attempts(username):
    """Clear failed login attempts after successful login."""
    if username in login_attempts:
        login_attempts[username] = {'count': 0, 'locked_until': None}


def validate_username(username):
    """Validate username format."""
    if not username or not isinstance(username, str):
        return False
    if len(username) < 3 or len(username) > 50:
        return False
    if not re.match(r'^[a-zA-Z0-9_]+$', username):
        return False
    return True


def validate_password(password):
    """Validate password is provided and reasonable length."""
    if not password or not isinstance(password, str):
        return False
    if len(password) < 8 or len(password) > 128:
        return False
    return True


def login_required(f):
    """Decorator to require password authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not session.get('authenticated'):
            return redirect(url_for('login_page'))
        if session.get('session_expires_at'):
            expires = datetime.fromisoformat(session['session_expires_at'])
            if datetime.utcnow() > expires:
                session.clear()
                return redirect(url_for('login_page'))
        return f(*args, **kwargs)
    return decorated_function


def mfa_required(f):
    """Decorator to require full MFA verification for sensitive operations."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not session.get('authenticated'):
            return redirect(url_for('login_page'))
        if not session.get('mfa_verified'):
            # Check if within grace period
            mfa_initiated = session.get('mfa_initiated_at')
            if mfa_initiated:
                initiated_time = datetime.fromisoformat(mfa_initiated)
                grace_remaining = (
                    initiated_time + timedelta(seconds=app.config['MFA_GRACE_PERIOD'])
                ) - datetime.utcnow()
                if grace_remaining.total_seconds() <= 0:
                    session.clear()
                    return jsonify({
                        'error': 'MFA verification timeout. Please login again.'
                    }), 401
            return redirect(url_for('verify_mfa_page'))
        return f(*args, **kwargs)
    return decorated_function


def generate_csrf_token():
    """Generate a CSRF token and store in session."""
    if '_csrf_token' not in session:
        session['_csrf_token'] = secrets.token_hex(32)
    return session['_csrf_token']


def validate_csrf_token(token):
    """Validate the CSRF token."""
    expected = session.get('_csrf_token')
    if not expected or not token:
        return False
    return hmac.compare_digest(expected, token)


app.jinja_env.globals['csrf_token'] = generate_csrf_token


