@app.route('/')
def index():
    if session.get('authenticated'):
        return redirect(url_for('dashboard'))
    return redirect(url_for('login_page'))


@app.route('/login', methods=['GET', 'POST'])
def login_page():
    if session.get('authenticated'):
        return redirect(url_for('dashboard'))

    if request.method == 'GET':
        return render_template_string(LOGIN_TEMPLATE, error=None, info=None)

    # CSRF validation
    csrf_token = request.form.get('csrf_token', '')
    if not validate_csrf_token(csrf_token):
        return render_template_string(LOGIN_TEMPLATE, error='Invalid request. Please try again.', info=None), 403

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')

    # Input validation
    if not validate_username(username):
        return render_template_string(
            LOGIN_TEMPLATE,
            error='Invalid username format.',
            info=None
        ), 400

    if not validate_password(password):
        return render_template_string(
            LOGIN_TEMPLATE,
            error='Invalid password format.',
            info=None
        ), 400

    # Check account lockout
    if is_account_locked(username):
        return render_template_string(
            LOGIN_TEMPLATE,
            error='Account is temporarily locked due to too many failed attempts. Please try again later.',
            info=None
        ), 429

    # Verify credentials - use constant-time comparison approach
    user = users_db.get(username)
    if not user or not check_password_hash(user['password_hash'], password):
        record_failed_attempt(username)
        # Generic error message to prevent username enumeration
        return render_template_string(
            LOGIN_TEMPLATE,
            error='Invalid username or password.',
            info=None
        ), 401

    # Password verified - create session with limited access
    clear_failed_attempts(username)

    # Regenerate session to prevent session fixation
    session.clear()
    session.regenerate = True
    session['authenticated'] = True
    session['username'] = username
    session['mfa_verified'] = False
    session['session_start'] = datetime.utcnow().isoformat()
    session['session_expires_at'] = (datetime.utcnow() + timedelta(minutes=30)).isoformat()
    session['mfa_initiated_at'] = datetime.utcnow().isoformat()
    session['mfa_attempts'] = 0
    session.permanent = True

    # Generate and "send" MFA code for email/SMS based MFA
    # (In addition to TOTP support)
    if user.get('mfa_enabled'):
        return redirect(url_for('verify_mfa_page'))

    # If MFA not enabled, grant full access
    session['mfa_verified'] = True
    return redirect(url_for('dashboard'))


@app.route('/verify-mfa', methods=['GET', 'POST'])
@login_required
def verify_mfa_page():
    if session.get('mfa_verified'):
        return redirect(url_for('dashboard'))

    username = session.get('username')
    user = users_db.get(username)

    if not user:
        session.clear()
        return redirect(url_for('login_page'))

    # Check MFA grace period
    mfa_initiated = session.get('mfa_initiated_at')
    if mfa_initiated:
        initiated_time = datetime.fromisoformat(mfa_initiated)
        if datetime.utcnow() > initiated_time + timedelta(seconds=app.config['MFA_GRACE_PERIOD']):
            session.clear()
            return redirect(url_for('login_page'))

    if request.method == 'GET':
        return render_template_string(MFA_VERIFY_TEMPLATE, error=None, info='Enter your TOTP code.')

    # CSRF validation
    csrf_token = request.form.get('csrf_token', '')
    if not validate_csrf_token(csrf_token):
        return render_template_string(
            MFA_VERIFY_TEMPLATE,
            error='Invalid request. Please try again.',
            info=None
        ), 403

    mfa_code = request.form.get('mfa_code', '').strip()

    # Validate MFA code format
    if not re.match(r'^\d{6}$', mfa_code):
        return render_template_string(
            MFA_VERIFY_TEMPLATE,
            error='Invalid code format. Please enter a 6-digit code.',
            info=None
        ), 400

    # Rate limit MFA attempts
    mfa_attempts = session.get('mfa_attempts', 0)
    if mfa_attempts >= 5:
        session.clear()
        return render_template_string(
            LOGIN_TEMPLATE,
            error='Too many MFA attempts. Please login again.',
            info=None
        ), 429

    # Verify TOTP code
    if verify_totp(user['mfa_secret'], mfa_code):
        session['mfa_verified'] = True
        session['mfa_verified_at'] = datetime.utcnow().isoformat()
        session['mfa_attempts'] = 0
        # Refresh session expiry on full authentication
        session['session_expires_at'] = (datetime.utcnow() + timedelta(minutes=30)).isoformat()
        return redirect(url_for('dashboard'))

    session['mfa_attempts'] = mfa_attempts + 1
    remaining = 5 - session['mfa_attempts']
    return render_template_string(
        MFA_VERIFY_TEMPLATE,
        error=f'Invalid MFA code. {remaining} attempts remaining.',
        info=None
    ), 401


